import boto3
from selenium import webdriver
from PIL import Image
from io import BytesIO
import base64
import os

def take_screenshot(url):
    # Setup Chrome WebDriver with headless mode
    chrome_options = webdriver.ChromeOptions()
    chrome_options.add_argument('--headless')
    chrome_options.add_argument('--disable-gpu')
    chrome_options.binary_location = os.environ.get("GOOGLE_CHROME_BIN")
    
    driver = webdriver.Chrome(executable_path=os.environ.get('CHROMEDRIVER_PATH'), options=chrome_options)

    # Navigate to URL
    driver.get(url)

    # Take screenshot and save as PNG in memory
    png = driver.get_screenshot_as_png()
    
    driver.quit()

    image = Image.open(BytesIO(png))

    # Resize the screenshot to thumbnail size
    image.thumbnail((300, 200))

    # Save resized image in memory and convert it into base64 string for S3 uploading
    temp_file = BytesIO()
    image.save(temp_file, 'JPEG')
    temp_file.seek(0)
    screenshot_base64 = base64.b64encode(temp_file.read())
    
    return screenshot_base64

def upload_to_s3(screenshot):
    # Create S3 client
    s3 = boto3.client('s3', region_name='us-west-2')

    # Upload the file to S3 bucket
    s3.put_object(Body=screenshot, Bucket='mybucket', Key='screenshots/test.jpg')
    
url = "https://www.example.com"
screenshot = take_screenshot(url)
upload_to_s3(screenshot)